PROCEDURE SystemCallTransition(syscall_number, parameters)
BEGIN
    // This runs in User Mode
    // User process prepares system call number and parameters

    // Trigger system call (software interrupt/trap)
    TRAP syscall_number

    // CPU now switches to Kernel Mode automatically
    // Control transfers here (Kernel Mode)

    // Kernel validates the request
    IF NOT ValidRequest(current_process, syscall_number) THEN
        RETURN ErrorCode
    END IF

    // Kernel performs the actual operation
    result = KernelHandler(syscall_number, parameters)

    // Return to User Mode
    RETURN result
    // CPU switches mode bit back to User Mode
END

