ALGORITHM PrivilegedInstructionExecution
BEGIN
    // This algorithm runs on CPU hardware

    WHEN instruction_fetched(instruction) DO
    BEGIN
        // Check if instruction is privileged
        IF instruction.type == PRIVILEGED THEN
        BEGIN
            // Check current privilege level (CPL) from CS register
            // Check required privilege level (RPL) from instruction or descriptor

            IF CPL > RPL THEN  // CPL is less privileged
            BEGIN
                // User Mode trying to execute privileged instruction
                // Generate Protection Fault (Trap to Kernel)

                TRAP #Protection_Fault
                // CPU switches to Kernel Mode (Ring 0)
                // OS handles the violation
                // Typically terminates the offending process
            END
            ELSE
            BEGIN
                // Running in Kernel Mode with sufficient privileges
                // Execute the privileged instruction normally
                EXECUTE instruction
            END
        END
        ELSE
        BEGIN
            // Non-privileged instruction - can execute in any mode
            EXECUTE instruction
        END
    END
END
